/**
 * Complete Curriculum Map
 * ========================
 * Defines all domains, subjects, and subtopics for the platform.
 * Phase A → Active now (questions generated by AI)
 * Phase B → Coming Soon (unlocked next semester)
 * Phase C → Coming Soon (unlocked later)
 *
 * TO UNLOCK A SUBJECT: change comingSoon: false
 * No other code changes needed anywhere.
 */

export interface Subtopic {
  id: string;
  name: string;
}

export interface Subject {
  id: string;
  name: string;
  skillField: string; // maps to skill_vector column
  subtopics: Subtopic[];
  comingSoon: boolean;
}

export interface Domain {
  id: string;
  name: string;
  phase: "A" | "B" | "C";
  comingSoon: boolean;
  subjects: Subject[];
}

