// ─── Helper exports ───────────────────────────────────────────────────────────

export const allDomains = curriculum.map(d => d.name);

export const activeDomains = curriculum.filter(d => !d.comingSoon);

export const allSubjects = curriculum.flatMap(d => d.subjects);

export const activeSubjects = allSubjects.filter(s => !s.comingSoon);

export const getSubjectById = (id: string) =>
  allSubjects.find(s => s.id === id);

export const getSubtopicsBySubject = (subjectId: string) =>
  getSubjectById(subjectId)?.subtopics ?? [];